param([string]$BaseUrl="http://localhost:18116",[Alias("OutputDir")][string]$OutDir="artifacts/test-reports/v0.9.11-dynamic-ml-dispatch/artifact-evidence",[switch]$SkipCompile)
$ErrorActionPreference="Stop";$root=(Resolve-Path (Join-Path $PSScriptRoot "..")).Path;$out=Join-Path $root $OutDir;New-Item -ItemType Directory -Force -Path $out|Out-Null
$headers=@{"X-Api-Key"="demo-key";"X-Tenant-Id"="demo"};function Post($u,$b){Invoke-RestMethod -Method Post -Uri $u -Headers $headers -ContentType "application/json" -Body ($b|ConvertTo-Json -Depth 30) -TimeoutSec 120};function Get($u){Invoke-RestMethod -Method Get -Uri $u -Headers $headers -TimeoutSec 120}
if(-not $SkipCompile){Push-Location $root;try{.\gradlew.bat compileJava --no-daemon --console=plain *> (Join-Path $out "compileJava.log")}finally{Pop-Location}}
$job=Post "$BaseUrl/api/v1/live/jobs" @{jobId="artifact-gate";tenantId="demo"};Post "$BaseUrl/api/v1/live/jobs/$($job.jobId)/orders" @{orders=@(@{orderId="ART-ORD-1";pickup=@{lat=10.1;lng=106.1};dropoff=@{lat=10.2;lng=106.2};deadline="2026-05-20T10:30:00Z";load=1;priority="HIGH"})}|Out-Null;Post "$BaseUrl/api/v1/live/jobs/$($job.jobId)/drivers/D01/telemetry" @{driverId="D01";lat=10.12;lng=106.12;status="EN_ROUTE";currentStopId="PICKUP:ART-ORD-1"}|Out-Null;$cycle=Post "$BaseUrl/api/v1/live/jobs/$($job.jobId)/cycle" @{returnDiagnostics=$true};$state=Get "$BaseUrl/api/v1/live/jobs/$($job.jobId)/state"
$state|ConvertTo-Json -Depth 100|Set-Content -Encoding UTF8 (Join-Path $out "live-state.json");$cycle|ConvertTo-Json -Depth 100|Set-Content -Encoding UTF8 (Join-Path $out "cycle-result.json");$cycle.diagnostics|ConvertTo-Json -Depth 100|Set-Content -Encoding UTF8 (Join-Path $out "ml-decision-trace.json");@{forecastUsed=$cycle.forecastUsed;forecastRiskCount=$cycle.diagnostics.forecastRiskCount}|ConvertTo-Json|Set-Content -Encoding UTF8 (Join-Path $out "forecast-risk.json");@{greedRlAction=$cycle.greedRlAction;greedRlActionUsed=$cycle.diagnostics.greedRlActionUsed}|ConvertTo-Json|Set-Content -Encoding UTF8 (Join-Path $out "greedrl-actions.json");@{triModelRepairUsed=$cycle.triModelRepairUsed;tabularInferenceCount=$cycle.diagnostics.tabularInferenceCount;routefinderCandidateCount=$cycle.diagnostics.routefinderCandidateCount}|ConvertTo-Json|Set-Content -Encoding UTF8 (Join-Path $out "tri-model-repair.json");@{routes=$cycle.routes;frozenStopIds=$state.frozenStopIds}|ConvertTo-Json -Depth 100|Set-Content -Encoding UTF8 (Join-Path $out "route-delta.json");$state.events|ConvertTo-Json -Depth 100|Set-Content -Encoding UTF8 (Join-Path $out "events.json")
$files=@("live-state.json","cycle-result.json","ml-decision-trace.json","forecast-risk.json","greedrl-actions.json","tri-model-repair.json","route-delta.json","events.json");$summaryPath=Join-Path $out "dynamic-artifact-summary.json";$s=[pscustomobject]@{version="v0.9.11-dynamic-ml-dispatch";gate="dynamic-artifact-evidence";generatedAt=(Get-Date).ToUniversalTime().ToString("o");compileJava=if($SkipCompile){"SKIPPED"}else{"PASS"};artifactCount=(Get-ChildItem $out -Filter *.json).Count;liveStateArtifactPresent=(Test-Path (Join-Path $out "live-state.json"));cycleResultArtifactPresent=(Test-Path (Join-Path $out "cycle-result.json"));mlTraceArtifactPresent=(Test-Path (Join-Path $out "ml-decision-trace.json"));forecastRiskArtifactPresent=(Test-Path (Join-Path $out "forecast-risk.json"));greedRlActionArtifactPresent=(Test-Path (Join-Path $out "greedrl-actions.json"));eventArtifactPresent=(Test-Path (Join-Path $out "events.json"));summaryArtifactPresent=$true;artifactReadable=$true;overallPass=$false}
foreach($f in $files){try{Get-Content (Join-Path $out $f) -Raw|ConvertFrom-Json|Out-Null}catch{$s.artifactReadable=$false}};$s.overallPass=$s.artifactCount -gt 0 -and $s.liveStateArtifactPresent -and $s.cycleResultArtifactPresent -and $s.mlTraceArtifactPresent -and $s.forecastRiskArtifactPresent -and $s.greedRlActionArtifactPresent -and $s.eventArtifactPresent -and $s.summaryArtifactPresent -and $s.artifactReadable;$s|ConvertTo-Json -Depth 100|Set-Content -Encoding UTF8 $summaryPath;if(-not $s.overallPass){throw "artifact gate FAIL"};Write-Host "[DYNAMIC-ARTIFACT] PASS"
